# Local data fallback URL (used only if Kaggle input path does not exist).
DATA_URL = "https://lucinda-bizonal-rhythmlessly.ngrok-free.dev/train.csv"

# Preferred: attach Kaggle dataset that contains train.csv at this path.
KAGGLE_INPUT_DATA_PATH = "/kaggle/input/digit-recognizer/train.csv"
PROJECT_DATA_PATH = "digit-recognizer/train.csv"
ALLOW_DOWNLOAD_FALLBACK = True

WORKDIR = Path("/kaggle/working")
PROJECT_ROOT = WORKDIR / "project_src"
OUTPUT_DIR = WORKDIR / "outputs"
KEEP_WORKING_ARTIFACTS = os.environ.get("KEEP_KAGGLE_WORKING_ARTIFACTS", "0") == "1"

PROJECT_FILES = {"config.yaml":"","main.py":"","requirements.txt":"bnVtcHk+PTEuMjQuMApwYW5kYXM+PTIuMC4wCnRvcmNoPj0yLjAuMAptYXRwbG90bGliPj0zLjcuMApQeVlBTUw+PTYuMC4wCm1sZmxvdz49Mi4wLjAKZmxhc2s+PTMuMC4wCnJlcXVlc3RzPj0yLjMxLjAKcHluZ3Jvaz49Ny4wLjAK","src/__init__.py":"IiIiR0FOIHByb2plY3QgcGFja2FnZS4iIiIK","src/config.py":"","src/data/__init__.py":"IiIiRGF0YSBtb2R1bGUgaW5pdGlhbGl6YXRpb24uIiIiCgpmcm9tIC5wcmVwcm9jZXNzaW5nIGltcG9ydCBsb2FkX2FuZF9wcmVwcm9jZXNzX2RhdGEKCl9fYWxsX18gPSBbImxvYWRfYW5kX3ByZXByb2Nlc3NfZGF0YSJdCg==","src/data/preprocessing.py":"","src/models/__init__.py":"IiIiTW9kZWxzIG1vZHVsZSBpbml0aWFsaXphdGlvbi4iIiIKCmZyb20gLm1vZGVsIGltcG9ydCBHZW5lcmF0b3IsIERpc2NyaW1pbmF0b3IKCl9fYWxsX18gPSBbIkdlbmVyYXRvciIsICJEaXNjcmltaW5hdG9yIl0K","src/models/model.py":"","src/training/__init__.py":"IiIiVHJhaW5pbmcgbW9kdWxlIGluaXRpYWxpemF0aW9uLiIiIgoKZnJvbSAudHJhaW4gaW1wb3J0IEdBTlRyYWluZXIKCl9fYWxsX18gPSBbIkdBTlRyYWluZXIiXQo=","src/training/train.py":"","src/utils/__init__.py":"","src/utils/helpers.py":""}


def run(cmd: list[str], cwd: Path | None = None, extra_env: dict[str, str] | None = None) -> None:
    print(f"+ {' '.join(cmd)}")
    env = os.environ.copy()
    if extra_env:
        env.update(extra_env)
    subprocess.check_call(cmd, cwd=str(cwd) if cwd else None, env=env)


def materialize_project_files() -> Path:
    if PROJECT_ROOT.exists():
        shutil.rmtree(PROJECT_ROOT)
    PROJECT_ROOT.mkdir(parents=True, exist_ok=True)

    for rel, encoded in PROJECT_FILES.items():
        target = PROJECT_ROOT / rel
        target.parent.mkdir(parents=True, exist_ok=True)
        target.write_bytes(base64.b64decode(encoded))

    return PROJECT_ROOT


def download_dataset(destination: Path) -> None:
    destination.parent.mkdir(parents=True, exist_ok=True)
    response = requests.get(
        DATA_URL,
        headers={"ngrok-skip-browser-warning": "true"},
        timeout=300,
    )
    response.raise_for_status()
    destination.write_bytes(response.content)
    print(f"Dataset downloaded: {destination}")


def resolve_data_path(project_root: Path) -> Path:
    if KAGGLE_INPUT_DATA_PATH:
        kaggle_input_file = Path(KAGGLE_INPUT_DATA_PATH)
        if kaggle_input_file.exists():
            print(f"Using Kaggle input dataset: {kaggle_input_file}")
            return kaggle_input_file

    project_data_file = project_root / PROJECT_DATA_PATH
    if project_data_file.exists():
        print(f"Using existing project dataset: {project_data_file}")
        return project_data_file

    if not ALLOW_DOWNLOAD_FALLBACK:
        raise RuntimeError(
            "Dataset not found in Kaggle input or project path and ALLOW_DOWNLOAD_FALLBACK is False."
        )

    if "<your-fixed-domain>" in DATA_URL:
        raise RuntimeError(
            "Set DATA_URL in run_kaggle.py to your real local ngrok /train.csv URL."
        )

    print("Dataset not found locally; downloading from DATA_URL...")
    download_dataset(project_data_file)
    return project_data_file


def write_kaggle_config(project_root: Path, data_path: Path) -> Path:
    base_config = project_root / "config.yaml"
    with base_config.open("r", encoding="utf-8") as handle:
        cfg = yaml.safe_load(handle)

    cfg["data"]["path"] = str(data_path)
    cfg["runtime"]["device"] = "cuda"
    cfg["output"]["dir"] = str(OUTPUT_DIR)
    mlflow_cfg = cfg.get("mlflow", {}) or {}
    if mlflow_cfg.get("enabled", False):
        mlflow_cfg["tracking_uri"] = str(OUTPUT_DIR / "mlruns")
        cfg["mlflow"] = mlflow_cfg

    config_out = WORKDIR / "config_kaggle.yaml"
    with config_out.open("w", encoding="utf-8") as handle:
        yaml.safe_dump(cfg, handle, sort_keys=False)

    print(f"Kaggle config written: {config_out}")
    return config_out


def cleanup_working_artifacts(project_root: Path, config_path: Path | None) -> None:
    """Delete temporary files so kernel outputs stay small."""
    if KEEP_WORKING_ARTIFACTS:
        print("Keeping temporary working artifacts for debugging.")
        return

    if config_path and config_path.exists():
        config_path.unlink()
        print(f"Removed temp config: {config_path}")

    if project_root.exists():
        shutil.rmtree(project_root)
        print(f"Removed temp project tree: {project_root}")


def main() -> None:
    project_root = PROJECT_ROOT
    config_path: Path | None = None
    try:
        project_root = materialize_project_files()

        requirements = project_root / "requirements.txt"
        run([sys.executable, "-m", "pip", "install", "-r", str(requirements)])

        data_path = resolve_data_path(project_root)

        config_path = write_kaggle_config(project_root, data_path)
        run(
            [sys.executable, "main.py", "--config", str(config_path)],
            cwd=project_root,
            extra_env={"PYTHONDONTWRITEBYTECODE": "1"},
        )

        print(f"DONE. Outputs are in: {OUTPUT_DIR}")
    finally:
        cleanup_working_artifacts(project_root, config_path)


if __name__ == "__main__":
    main()

